return items.map(item => {
  const topic = item.json;
  const first = topic.post_stream?.posts?.find(p => p.post_number === 1);
  return {
    json: {
      id: topic.id,
      title: topic.title,
      url: `https://forum.livepeer.org/t/${topic.id}`,
      authorName: first?.name || first?.username || "Unknown",
      authorUsername: first?.username || "unknown",
      body: first?.cooked || "",
      replyCount: topic.posts_count - 1 || 0, // Subtract 1 for original post
      createdAt: topic.created_at || first?.created_at || "",
      updatedAt: topic.updated_at || first?.updated_at || ""
    }
  };
});

function isOldPinned(t) {
  const pinned = t.json.pinned === true || t.json.pinned_globally === true;
  if (!pinned) return false;
  const created = new Date(t.json.created_at);
  const now = new Date();
  const ageDays = (now - created) / (1000 * 60 * 60 * 24);
  return ageDays > 30;
}

let topics = items.filter(t => !isOldPinned(t));
const top4 = topics.slice(0, 4);
return top4;

