const topics = items[0].json.topics;
const forumData = [];

// HTML cleaner function - keeps basic HTML formatting
function cleanAndFormatHTML(html) {
  let cleanHTML = html;

  // Remove anchor navigation links
  cleanHTML = cleanHTML.replace(/<a[^>]*name="[^"]*"[^>]*class="anchor"[^>]*>.*?<\/a>/g, '');

  // Clean up headings
  cleanHTML = cleanHTML.replace(/<h1[^>]*>(.*?)<\/h1>/g, '<h3>$1</h3>');
  cleanHTML = cleanHTML.replace(/<h2[^>]*>(.*?)<\/h2>/g, '<h4>$1</h4>');
  cleanHTML = cleanHTML.replace(/<h3[^>]*>(.*?)<\/h3>/g, '<h5>$1</h5>');
  cleanHTML = cleanHTML.replace(/<h[4-6][^>]*>(.*?)<\/h[4-6]>/g, '<h6>$1</h6>');

  // Clean up images and their references
  cleanHTML = cleanHTML.replace(/<a[^>]*class="lightbox"[^>]*>.*?<\/a>/g, ''); // Remove lightbox wrappers
  cleanHTML = cleanHTML.replace(/<div[^>]*class="lightbox-wrapper"[^>]*>.*?<\/div>/g, ''); // Remove lightbox divs
  cleanHTML = cleanHTML.replace(/<img[^>]*>/g, ''); // Remove img tags
  cleanHTML = cleanHTML.replace(/\[!\[.*?\]\(.*?\)\]\(.*?\)/g, ''); // Remove markdown image links
  cleanHTML = cleanHTML.replace(/image\d+×\d+\s+[\d.]+\s*[KM]B/gi, ''); // Remove image size text

  // Keep paragraphs, lists, emphasis, code
  cleanHTML = cleanHTML.replace(/<p>/g, '<p>');
  cleanHTML = cleanHTML.replace(/<\/p>/g, '</p>');
  cleanHTML = cleanHTML.replace(/<ul>/g, '<ul>');
  cleanHTML = cleanHTML.replace(/<\/ul>/g, '</ul>');
  cleanHTML = cleanHTML.replace(/<li>/g, '<li>');
  cleanHTML = cleanHTML.replace(/<\/li>/g, '</li>');
  cleanHTML = cleanHTML.replace(/<strong>(.*?)<\/strong>/g, '<strong>$1</strong>');
  cleanHTML = cleanHTML.replace(/<em>(.*?)<\/em>/g, '<em>$1</em>');
  cleanHTML = cleanHTML.replace(/<code>(.*?)<\/code>/g, '<code>$1</code>');

  // Simplify links
  cleanHTML = cleanHTML.replace(/<a[^>]*href="([^"]*)"[^>]*>(.*?)<\/a>/g, '<a href="$1" target="_blank">$2</a>');

  // Decode HTML entities
  cleanHTML = cleanHTML.replace(/&amp;/g, '&');
  cleanHTML = cleanHTML.replace(/&lt;/g, '<');
  cleanHTML = cleanHTML.replace(/&gt;/g, '>');
  cleanHTML = cleanHTML.replace(/&quot;/g, '"');
  cleanHTML = cleanHTML.replace(/&#39;/g, "'");
  cleanHTML = cleanHTML.replace(/&nbsp;/g, ' ');

  // Clean up whitespace
  cleanHTML = cleanHTML.replace(/\s+/g, ' ');
  cleanHTML = cleanHTML.replace(/<p>\s*<\/p>/g, '');

  cleanHTML = cleanHTML.trim();

  return cleanHTML;
}

for (const t of topics) {
  // Convert to clean HTML
  const htmlContent = cleanAndFormatHTML(t.body);

  // Format the date nicely
  const datePosted = t.createdAt ? new Date(t.createdAt).toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'short',
    day: 'numeric'
  }) : '';

  forumData.push({
    title: t.title,
    href: t.url,
    author: `By ${t.authorName} (@${t.authorUsername})`,
    content: htmlContent, // Clean HTML
    replyCount: t.replyCount || 0,
    datePosted: datePosted
  });
}

// Generate the JavaScript export string
let jsExport = 'export const forumData = [\n';
forumData.forEach((item, index) => {
  jsExport += '  {\n';

  // Title
  jsExport += `    title: '${item.title.replace(/\\/g, '\\\\').replace(/'/g, "\\'")}',\n`;

  // URL
  jsExport += `    href: '${item.href}',\n`;

  // Author
  jsExport += `    author: '${item.author.replace(/\\/g, '\\\\').replace(/'/g, "\\'")}',\n`;

  // Content - HTML, properly escaped for JS string
  const escapedContent = item.content
    .replace(/\\/g, '\\\\')
    .replace(/'/g, "\\'")
    .replace(/"/g, '\\"')
    .replace(/\n/g, '\\n')
    .replace(/\r/g, '\\r')
    .replace(/\t/g, '\\t');
  jsExport += `    content: '${escapedContent}',\n`;

  // Reply count
  jsExport += `    replyCount: ${item.replyCount},\n`;

  // Date posted
  jsExport += `    datePosted: '${item.datePosted}',\n`;

  jsExport += '  }';
  if (index < forumData.length - 1) {
    jsExport += ',';
  }
  jsExport += '\n';
});
jsExport += '];\n';

return [{ json: { fileContent: jsExport } }];
